<template>
  <div>
    <a-layout>
      <a-layout-content
        :style="{ background: '#fff', padding: '24px', margin: 0, minHeight: '280px' }"
      >
        <p>
          <a-form layout="inline" :model="param">
            <a-form-item>
              <a-input v-model:value="param.name" placeholder="名称" />
            </a-form-item>
            <a-form-item>
              <a-button type="primary" @click="handleQuery({ page: 1, size: pagination.pageSize })">
                查询
              </a-button>
            </a-form-item>
            <a-form-item>
              <a-button type="primary" @click="add()">
                新增
              </a-button>
            </a-form-item>
          </a-form>
        </p>
        <a-table
          :columns="columns"
          :row-key="record => record.id"
          :data-source="ebooks"
          :pagination="pagination"
          :loading="loading"
          @change="handleTableChange"
        >
          <template #bodyCell="{ column, record }">
            <template v-if="column.key === 'cover'">
              <a-image
                :src="record.cover"
                alt="图片加载失败"
                style="width:80px;height:80px"
                :fallback="'data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 80 80%22%3E%3Crect fill=%22%23f0f0f0%22 width=%2280%22 height=%2280%22/%3E%3Ctext x=%2240%22 y=%2240%22 text-anchor=%22middle%22 dy=%22.3em%22 fill=%22%23ccc%22 font-size=%2212%22%3E无封面%3C/text%3E%3C/svg%3E'"
              />
            </template>
            <template v-if="column.key === 'category'">
              <span>
                {{ getCategoryName(record.category1Id) }}
                <template v-if="record.category2Id"> / {{ getCategoryName(record.category2Id) }}</template>
              </span>
            </template>
            <!-- 操作列 -->
            <template v-if="column.dataIndex === 'action'">
              <a-space size="small">
                <!-- 文档管理按钮（携带电子书 ID） -->
                <a-button type="primary">
                  <router-link :to="'/admin/doc?ebookId=' + record.id">
                    文档管理
                  </router-link>
                </a-button>
                <a-button type="primary" @click="edit(record)">
                  编辑
                </a-button>
                <a-popconfirm
                  title="删除后不可以恢复，确认删除?"
                  ok-text="是"
                  cancel-text="否"
                  @confirm="handleDelete(record.id)"
                >
                  <a-button type="danger">
                    删除
                  </a-button>
                </a-popconfirm>
              </a-space>
            </template>
          </template>
        </a-table>
      </a-layout-content>
    </a-layout>

    <!-- 编辑模态框 -->
    <a-modal
      title="电子书表单"
      v-model:open="modalVisible"
      :confirm-loading="modalLoading"
      @ok="handleModalOk"
    >
      <a-form :model="ebook" :label-col="{ span: 6 }" :wrapper-col="{ span: 18 }">
        <a-form-item label="封面">
          <a-input v-model:value="ebook.cover" />
        </a-form-item>
        <a-form-item label="名称">
          <a-input v-model:value="ebook.name" />
        </a-form-item>

        <!-- 分类级联选择器 -->
        <a-form-item label="分类">
          <a-cascader
            v-model:value="categoryIds"
            :field-names="{ label: 'name', value: 'id', children: 'children' }"
            :options="level1"
            placeholder="请选择分类"
            style="width: 100%"
            expand-trigger="hover"
            change-on-select
          />
        </a-form-item>

        <a-form-item label="描述">
          <a-textarea v-model:value="ebook.description" />
        </a-form-item>
      </a-form>
    </a-modal>
  </div>
</template>

<script setup>
import axios from 'axios'
import { ref, onMounted } from 'vue'
import { message } from 'ant-design-vue'

// ---------- 数据定义 ----------
const ebooks = ref([])
const param = ref({ name: '' })
const loading = ref(false)
const pagination = ref({
  current: 1,
  pageSize: 5,
  total: 0
})

// 分类映射：用于根据 ID 获取名称
const categoryMap = ref({})
// 树形分类数据（用于级联选择）
const level1 = ref([])
// 级联选择器选中的值
const categoryIds = ref([])

// 表格列配置
const columns = [
  { title: '封面', key: 'cover', dataIndex: 'cover' },
  { title: '名称', dataIndex: 'name' },
  { title: '分类', key: 'category' },
  { title: '文档数', dataIndex: 'docCount' },
  { title: '阅读数', dataIndex: 'viewCount' },
  { title: '点赞数', dataIndex: 'voteCount' },
  { title: '操作', key: 'action', dataIndex: 'action' }
]

const modalVisible = ref(false)
const modalLoading = ref(false)
const ebook = ref({
  id: null,
  cover: '',
  name: '',
  category1Id: '',
  category2Id: '',
  description: ''
})

// ---------- 树形结构构建函数 ----------
const buildTree = (list, parentId = 0) => {
  const pid = String(parentId)
  return list
    .filter(item => String(item.parent) === pid)
    .map(item => ({
      ...item,
      children: buildTree(list, item.id)
    }))
}

// ---------- 根据分类 ID 获取名称 ----------
const getCategoryName = (id) => {
  if (id == null) return ''
  const key = String(id)
  return categoryMap.value[key] || ''
}

// ---------- 查询分类 ----------
const handleQueryCategory = () => {
  return axios.get('/category/all')
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        const rawList = data.content || []
        const map = {}
        rawList.forEach(item => {
          map[String(item.id)] = item.name
        })
        categoryMap.value = map
        level1.value = buildTree(rawList, 0)
        console.log('分类树：', level1.value)
        return Promise.resolve()
      } else {
        message.error(data.message || '加载分类失败')
        return Promise.reject(data.message)
      }
    })
    .catch((err) => {
      message.error('分类加载失败，请检查网络')
      return Promise.reject(err)
    })
}

// ---------- 查询电子书列表 ----------
const handleQuery = (params) => {
  loading.value = true
  axios.get('/ebook/list', {
    params: {
      page: params.page,
      size: params.size,
      name: param.value.name
    }
  })
    .then((resp) => {
      loading.value = false
      const data = resp.data
      const content = data.content || { list: [], total: 0 }
      const list = content.list || []
      ebooks.value = Array.isArray(list) ? list : []
      pagination.value.total = content.total || 0
      pagination.value.current = params.page
    })
    .catch((err) => {
      loading.value = false
      ebooks.value = []
      console.error('请求失败:', err)
    })
}

// ---------- 分页变化 ----------
const handleTableChange = (paginationInfo) => {
  handleQuery({
    page: paginationInfo.current,
    size: paginationInfo.pageSize
  })
}

// ---------- 编辑 ----------
const edit = (record) => {
  modalVisible.value = true
  ebook.value = { ...record }
  const path = []
  if (record.category1Id) path.push(String(record.category1Id))
  if (record.category2Id) path.push(String(record.category2Id))
  categoryIds.value = path
}

// ---------- 新增 ----------
const add = () => {
  modalVisible.value = true
  ebook.value = { id: null, cover: '', name: '', description: '' }
  categoryIds.value = []
}

// ---------- 保存 ----------
const handleModalOk = () => {
  modalLoading.value = true

  const ids = categoryIds.value || []
  ebook.value.category1Id = ids[0] || null
  ebook.value.category2Id = ids[1] || null

  const isEdit = ebook.value.id !== null && ebook.value.id !== undefined
  const url = isEdit ? `/ebook/update/${ebook.value.id}` : '/ebook/save'
  const method = isEdit ? 'put' : 'post'
  const submitData = { ...ebook.value }
  if (isEdit) delete submitData.id

  axios[method](url, submitData)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        modalVisible.value = false
        modalLoading.value = false
        message.success(isEdit ? '更新成功' : '添加成功')
        handleQuery({
          page: pagination.value.current,
          size: pagination.value.pageSize
        })
      } else {
        modalLoading.value = false
        message.error(data.message || '操作失败')
      }
    })
    .catch((err) => {
      modalLoading.value = false
      console.error('保存失败:', err)
      message.error('保存失败，请重试')
    })
}

// ---------- 删除 ----------
const handleDelete = (id) => {
  loading.value = true
  axios.delete(`/ebook/delete/${id}`)
    .then((resp) => {
      loading.value = false
      const data = resp.data
      if (data.success) {
        message.success('删除成功')
        handleQuery({
          page: pagination.value.current,
          size: pagination.value.pageSize
        })
      } else {
        message.error(data.message || '删除失败')
      }
    })
    .catch((err) => {
      loading.value = false
      console.error('删除失败:', err)
      message.error('删除失败，请重试')
    })
}

// ---------- 生命周期 ----------
onMounted(() => {
  handleQueryCategory()
    .then(() => {
      handleQuery({ page: 1, size: pagination.value.pageSize })
    })
    .catch(() => {
      handleQuery({ page: 1, size: pagination.value.pageSize })
    })
})
</script>

<style scoped>
/* 样式可保留 */
</style>
